executeJS.function:
var input = document.evaluate(
    "{{inputXPathSelector}}",
    document,
    null,
    XPathResult.FIRST_ORDERED_NODE_TYPE,
    null
).singleNodeValue;
var datepicker = document.querySelector("{{datePickerWidgetSelector}}");

if (!input) {
    return 'Date input field not found';
}
if (!datepicker) {
    return 'Datepicker widget not found';
}

var inputRect = input.getBoundingClientRect();
var datepickerRect = datepicker.getBoundingClientRect();
var horizontalTolerance = Math.max(20, inputRect.width * 0.4);
var verticalTopTolerance = Math.max(5, inputRect.height * 0.3);
var maxBelowInput = datepickerRect.height + Math.max(10, inputRect.height * 0.25);
var horizontalAligned = Math.abs(datepickerRect.left - inputRect.left) < horizontalTolerance;
var verticalNear = datepickerRect.top >= inputRect.top - verticalTopTolerance
    && datepickerRect.top <= inputRect.bottom + maxBelowInput;

return (horizontalAligned && verticalNear)
    ? 'Datepicker is correctly positioned relative to input'
    : 'Datepicker is mispositioned relative to input';
